#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        if ((n * m) % 2 == 1 || (n % 2 == 1 && m % 2 == 0) || (n % 2 == 0 && m % 2 == 1)) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

