code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            if ((n * m) % 2 == 1 || (n % 2 == 1 && m % 2 == 0) || (n % 2 == 0 && m % 2 == 1)) {
                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }
}

